package com.bkrc.bkrcv3.adapter.gpt;

import com.bkrc.bkrcv3.required.Ai;
import com.bkrc.bkrcv3.common.dataserializer.DataSerializer;
import com.bkrc.bkrcv3.adapter.gpt.request.GptMessage;
import com.bkrc.bkrcv3.adapter.gpt.request.GptRequest;
import com.bkrc.bkrcv3.adapter.gpt.response.GptResponse;
import com.fasterxml.jackson.databind.ObjectMapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.util.CollectionUtils;

import java.util.List;
import java.util.Map;
import java.util.Optional;

@Service
@RequiredArgsConstructor
@Slf4j
public class Gpt implements Ai {
    private final GptClient gptClient;
    private final GptResponseParser gptResponseParser;
    private final ObjectMapper objectMapper;

    @Override
    public List<String> getRecommend(String bookTitle) {
        var msgs = List.of(
                new GptMessage("system", "너는 누군가의 작은 불씨를 살리는 책을 추천하는 역할이야. 그리고 책속의 3가지 이하의 명언이나 좋은 내용의 문장을 3가지 이하 소개하는 책임이 있어. 만약 소개할 수 없다면 null을 출력해줘."),
                new GptMessage("user", "참을 수 없는 존재의 가벼움"),
                new GptMessage("assistant", DataSerializer.serialize(Map.of(GptConstants.CHAT_RESPONSE_KEY, List.of("사랑은 힘을 빼는 것이다.", "한 번은 아무것도 아니다. 한 번뿐인 것은 전혀 있었던 것이 아니다.")))),
                new GptMessage("user", "노인과 바다"),
                new GptMessage("assistant", DataSerializer.serialize(Map.of(GptConstants.CHAT_RESPONSE_KEY, List.of("인간은 패배하도록 만들어지지 않았다. 인간은 파괴될 수는 있어도 패배하지는 않는다.", "지금은 생각할 때가 아니다. 지금은 해야 할 때다")))),
                new GptMessage("user", bookTitle)
        );

        return getChatResponse(msgs).map(gptResponseParser::parseStringList).orElse(List.of());
    }

    @Override
    public String filteringContent(String comment) {
        var msgs = List.of(
                new GptMessage("system", "너는 누군가의 작은 불씨를 살리는 책을 추천하는 역할이야. 그리고 내가 말해준 아래 책 내용에 대해 사용자가 읽었을때 구매할 수 있도록 단백한 문장으로 요약하는 책임이 있어"),
                new GptMessage("user", "매해 노벨 문학상 후보 목록에 오르는 작가인 동시에 인터뷰나 대외 활동을 자제하고 은둔을 자처하는 작가. 체코 출신으로 ‘프라하의 봄’을 직접 경험하고 집필 및 판매 금지 등 정치적 박해를 피해 프랑스로 망명한 작가. 현재에서 멀지 않은 20세기 작가이지만 이미 살아 있는 신화가 된 작가. 밀란 쿤데라에 대한 한국인의 사랑은 특별하다. 대표작 『참을 수 없는 존재의 가벼움』의 국내 총 판매량 100만 부에 달하며, 민음사에서는 밀란 쿤데라 전집(총 15권)을 출간하기도 했다. 쿤데라를 사랑하는 독자는 광고인 박웅현, 피아니스트 김대진, 화가 황주리, 소설가 김영하, 김연수 등 각계각층에서 다양하다. 특히 지난 2016년에는 네이버 ‘지식인의 서재’ 선정 ‘우리 시대 지식인이 사랑한 책’ TOP10에 들기도 했다. 쿤데라에 대한 격찬은 그의 소설이 프랑스어로 소개된 직후 서양 지식인들에서부터 시작되었다. 쿤데라의 첫 번째 소설인 『농담』 불어판 서문에서 시인 아라공은 쿤데라를 일컬어 “금세기 최고의 소설가들 중 한 사람, 소설이 빵과 마찬가지로 인간에게 없어서는 안 되는 것임을 증명해 주는 작가”라고 격찬하며 “우리 시대 어떤 작가도 필적할 수 없는 기교를 갖추었다.”라고 했다. 또한 샐먼 루시디는 쿤데라를 “명백히 세계적으로 가장 훌륭한 예술가”라 칭했다.\n" +
                        "이렇듯 명실공히 20세기를 아울러 현존하는 최고의 현대 소설가 중 한 명으로 꼽히는 쿤데라의 작품들은 거의 모두가 탁월한 문학적 깊이를 인정받아서 프랑스 메디치 상, 클레멘트 루케 상, 프레미오 레테라리오 몬델로 상, 유로파 상, 체코 작가연맹 상, 체코 작가출판사 상, 커먼웰스 상, LA타임스 소설 상, 두카 재단 상 등 수많은 문학상을 받았으며 해마다 노벨 문학상 후보 작가로 추천되고 있다. 미국 미시건 대학은 그의 문학적 공로를 높이 평가하면서 명예박사 학위를 수여했다.\n" +
                        "쿤데라 작품을 독점 계약, 출판하고 있는 민음사에서는 밀란 쿤데라 국내 소개 30주년을 맞아 『참을 수 없는 존재의 가벼움』 리뉴얼 판을 선보였다. 『참을 수 없는 존재의 가벼움』은 1988년 계간 《세계의 문학》 가을호에 전재되면서 우리나라에 처음 소개되었고, 발표 직후 1988년 11월 20일 단행본으로 출간되었다. 당시에는 독문학자 송동준 교수가 독일어 판본을 옮겨 펴냈으나, 1999년 2월에 불문학자 이재룡 교수의 변역으로 다시 펴냈다. 이는 원저자인 밀란 쿤데라의 요청에 따른 것으로, 쿤데라는 프랑스어 판본을 옮기는 것이 자신의 원작에 가장 충실한 것이라고 밝힌 바 있다. 새롭게 리뉴얼해 선보이는 『참을 수 없는 존재의 가벼움』은 그간 출간된 세계문학전집 및 작가 전집 버전과 달리 밀란 쿤데라가 직접 그린 일러스트를 바탕으로 디자인한 신선한 표지와 장정으로 21세기를 살아 나가는 젊은 독자들의 눈을 다시금 사로잡을 예정이다.\n" +
                        "\n" +
                        "존재를 관통하는 덧없는 사랑에 대한 잔혹한 메타포\n" +
                        "\n" +
                        "고향의 작은 술집에서 일하며 근근이 살던 젊은 테레자는 출장으로 그 도시에 들른 외과의사 토마시와 우연히 만난다. 서로 그 만남을 잊지 못할 만큼 운명적으로 생각하던 차, 테레자는 톨스토이의 『안나 카레니나』와 여행 가방만을 들고 그를 찾아간다. 전처와의 이혼 이후 진지한 사랑을 부담스러워하던 토마시는 ‘강물에 떠내려온 아기’ 같은 테레자의 연약한 매력을 놓지 못하고 고아를 떠맡듯 그녀와 함께 살기 시작한다. 하지만 스스로가 ‘에로틱한 우정’이라고 이름 붙인 그 ‘가벼운 삶’을 토마시는 버리지 못하고 이 여자 저 여자를 전전한다. 그런 토마시를 지켜보는 테레자는 질투와 체념으로 인한 괴로움에 몸부림친다. 소련의 침공으로 체코가 자유를 잃은 후, 두 사람은 함께 스위스로 넘어간다. 체코를 벗어나면 토마시의 연인들로부터도 벗어날 수 있을 거라 믿었던 테레자는, 토마시의 끊임없는 외도에 믿음을 잃은 후 홀로 국경을 넘어 프라하로 돌아간다. 질투와 미움이 뒤섞인 두 사람의 삶은 그렇게 점차 무게를 더해 간다.\n" +
                        "한편 토마시의 또다른 연인이자 화가인 사비나는 끈질기게 자신을 따라다니는 조국과 역사의 무게에서 벗어나 자유롭게 살고 싶어 한다. 밥을 먹어도, 그림을 그려도, 거리를 걸어도 자신에겐 ‘조국을 잃은 여자’라는 꼬리표가 붙는 것을 그녀는 견딜 수 없다. 사비나는 체코에서 멀리, 할 수 있는 한 가장 멀리 떠난다. 사비나를 사랑하는 학자이자 한 가정의 가장으로서 안정된 일상을 누리던 프란츠는 그런 사비나의 ‘가벼움’에 매료된다.\n" +
                        "무거운 역사의 상처와 개인적 트라우마를 어깨에 짊어진 이 네 남녀의 생과 사랑의 모습은, 오늘날 ‘참을 수 없는’ 생의 무거움과 가벼움을 오가며 방황하는 바로 우리 자신의 모습이기도 하다.\n" +
                        "\n" +
                        "되돌릴 수 없는 겨우 단 한 번의 생, 그 무의미함에 대하여\n" +
                        "\n" +
                        "“영원한 회귀가 주장하는 바는, 인생이란 한번 사라지면 두 번 다시 돌아오지 않기 때문에 한낱 그림자 같은 것이고, 그래서 산다는 것에는 아무런 무게도 없고 우리는 처음부터 죽은 것과 다름없어서, 삶이 아무리 잔혹하고 아름답고 혹은 찬란하다 할지라도 그 잔혹함과 아름다움과 찬란함조차도 무의미하다는 것이다.” - 본문 중에서\n" +
                        "\n" +
                        "『참을 수 없는 존재의 가벼움』에서 작가는 어떤 사랑 이야기, 특별한 동시에 잊을 수 없는 이야기를 들려준다. 테레사와 토마스는 우연히 서로 만나 평생을 각자의 방식으로 사랑을 이어 가다가 교통사고로 함께 죽는다. 그들의 운명은 필연적이지 않다. 결국 돌이킬 수 없는 결정들과 우연한 사건들과 어쩌다가 받아들이게 된 구속들의 축적이 낳은 산물에 불과하기 때문이다. 그럼에도 이 둘은 그 구속에 서로를 얽어매며 평생을 존재의 무게 속에서 살아 나간다.\n" +
                        "토마시는 이 작품 속에서 끊임없이 이렇게 되뇌인다. “사람이 무엇을 희구해야만 하는가를 안다는 것은 절대 불가능하다. 왜냐하면 사람은 한 번밖에 살지 못하고 전생과 현생을 비교할 수도 없으며 현생과 비교하여 후생을 바로잡을 수도 없기 때문이다. (…) 한 번뿐인 것은 전혀 없었던 것과 같다. 한 번만 산다는 것은 전혀 살지 않는다는 것과 마찬가지다.(Einmal ist Keinmal.)” 니체의 영원회귀 사상을 비튼 이 생각을 바탕으로 쿤데라는 ‘한 번인’ 동시에 ‘아무것도 아닌’ 이 삶의 무의미함을 철저하게 파헤친다.\n" +
                        "쿤데라는 니체의 영원회귀 사상이 의미하는 ‘가벼움’과 베토벤의 곡의 모티프 중 하나인 ‘그래야만 한다!(Es muss sein!)’의 ‘무거움’ 사이에서 방황하는 토마시의 모습을 그린다. 베토벤의 작품번호 135 마지막 4중주 4악장의 핵심 악장의 모티프인 ‘그래야만 한다!(Es muss sein!)’가 뜻하는 것은 구속, 당위이며 가벼운 것에서 무거운 것으로의 전이이다. 삶을 살아나가는 여러 태도 가운데 쿤데라는 삶의 이 모순된 무게를 저울질해 가며 방황하는 군상을 그려 나간다.\n" +
                        "\n" +
                        "밀란 쿤데라의 역사적, 철학적 사유가 오롯이 담긴 작품\n" +
                        "\n" +
                        "“역사란 개인의 삶만큼이나 가벼운, 참을 수 없을 정도로 가벼운, 깃털처럼 가벼운, 바람에 날리는 먼지처럼 가벼운, 내일이면 사라질 그 무엇처럼 가벼운 것이다.”\n" +
                        "- 본문 중에서\n" +
                        "\n" +
                        "한 사람의 인생이 역사에서 자유로울 수 있을까? 사소한 우연이든 의미심장한 우연이든, 우리는 그것을 운명으로 받아들여야 할까? 네 남녀의 사랑 이야기를 따라 흘러가는 이 소설의 배경에는 1960년대 체코와 1970년대 유럽을 뒤흔들어 놓은 시련이 깔려 있다. 지금은 멀어져 버렸지만 쿤데라의 작품 한복판에 주인공인 양 요지부동으로 박혀 있는 체코. 작가의 근원은 체코에 있었다. 쿤데라 자신 역시 자신의 조국에서 벌어진 비극과 개인적 박해를 오롯이 경험했고, 이 경험은 그의 작품 군데군데에 녹아 있다.\n" +
                        "하지만 동시에 쿤데라는 그의 최근 에세이 『커튼』을 통해 사회 운동, 전쟁, 혁명과 반혁명, 국가의 굴욕 등 역사 그 자체는 소설가가 그려야 할 대상, 고발하고 해석해야 할 대상이 아니라고 밝혔다. 소설가는 “역사가의 하인”이 아니며 소설가를 매혹하는 역사란, 오직 “인간 실존에 빛을 비추는 탐조등으로서의 역사”일 뿐이라는 것이다. 역사로서의 예술, 혹은 예술의 역사는 덧없으며 “예술의 지저귐은 영원할 것”이라는 쿤데라의 말처럼, 이 작품은 역사에서 태어났으되, 역사를 뛰어넘는 인간의 실존 그 자체를 다루고 있기 때문에 영원히 사랑받는 불멸의 고전으로 남을 것이다. "),
                new GptMessage("assistant", DataSerializer.serialize(Map.of(GptConstants.CHAT_RESPONSE_KEY, "밀란 쿤데라의 대표작 참을 수 없는 존재의 가벼움은 사랑과 욕망, 자유와 책임 사이에서 흔들리는 인간의 본질을 깊이 있게 그린다. 전 세계가 극찬한 이 작품은 단 한 번뿐인 삶의 의미를 묻는 강렬한 메시지로, 지금 읽어도 여전히 당신을 사로잡을 것이다."))),
                new GptMessage("user", "\n" +
                        "책소개\n" +
                        "노벨 문학상, 퓰리처상 수상 작가\n" +
                        "20세기 미국 문학을 개척한 작가 어니스트 헤밍웨이\n" +
                        "\n" +
                        "노벨 문학상을 수상한(1954) 미국의 소설가 어니스트 헤밍웨이의 대표작 『노인과 바다(The Old Man and the Sea)』를 비롯하여 『무기여 잘 있어라(A Farewell to Arms)』, 『태양은 다시 떠오른다(The Sun Also Rises)』가 민음사 세계문학전집으로 출간되었다. 미국 현대 문학의 개척자라 불리는 헤밍웨이는 제1차 세계대전 후 삶의 좌표를 잃어버린 ‘길 잃은 세대’(une g?n?ration perdue, lost generation)’를 대표하는 작가이다. 그러나 그동안 저작권 계약이 어려워, 국내에는 제대로 소개되지 못하다가 이번에 대표작 세 권을 동시에 선보이게 되었다. 헤밍웨이의 마지막 소설로, 작가 고유의 소설 수법과 실존 철학이 짧은 분량 안에 집약돼 있는 『노인과 바다』, 그 스스로 “내가 쓴 『로미오와 줄리엣』”이라 밝힌 연애소설이자 깊은 존재론적 성찰을 담은 『무기여 잘 있어라』, 세계대전 후 삶의 방향을 상실한 사람들을 그린 첫 번째 장편소설 『태양은 다시 떠오른다』 세 권이다.\n" +
                        "이는 또한 영문학자이자 번역가인 김욱동(한국외대 영어 통번역학과) 교수가 지난 3년간 준비해 온 결과이기도 하다. 헤밍웨이는 자신의 작품이 “바다 위에 떠 있는 빙산과 같아서 8분의 1에 해당하는 부분만이 수면에 떠 있고 나머지 8분의 7은 수면 아래 가라앉아 있다.”라고 말한 바 있는데, 김욱동 교수는 2009년부터 번역을 해 오면서 이러한 문체적 특성을 살리는 데 중점을 두었다. ‘하드보일드 스타일’이라 불리는 간결한 표현 속에 다양한 의미를 숨겨 둔 헤밍웨이의 문장 하나하나를 여러 각도로 고민하여 그 어감을 최대한 살리면서도 한국 독자들이 쉽게 이해할 수 있게 번역하려고 애썼다. 또한 프랑스어나 스페인어를 그대로 노출해 지역적 특징을 드러낸 부분도 원문 그대로, 그러나 그 의도와 느낌은 해치지 않도록 하는 데도 노력했다. 쿠바나 이탈리아, 스페인 등의 지명과 어업, 전쟁, 투우 등에 사용되는 용어들도 하나하나 조사하여 실어 주었다. 김욱동 교수는 “이 번역서들에서 헤밍웨이의 육체뿐만 아니라 그 영혼을 살려 내고 싶었다. 지시적인 의미를 전달하는 것에 그치지 않고 함축적 의미까지 옮기는 데 관심을 기울였다. 다시 말해 행간의 숨은 뜻을 놓치지 않으려고 애썼다.”라고 헤밍웨이 번역 과정의 마음가짐을 밝히기도 했다.\n" +
                        "\n" +
                        "■ 『노인과 바다』\n" +
                        "절제된 문장으로 강렬하게 그려 낸 한 노인의 실존적 투쟁과 불굴의 의지\n" +
                        "개인주의와 허무주의를 극복하고 인간과 자연을 긍정하고 진정한 연대의 가치를 역설한 수작\n" +
                        "\n" +
                        "멕시코 만류에서 홀로 고기잡이를 하는 노인 산티아고는 벌써 84일째 아무것도 잡지 못했다. 같은 마을에 사는 소년 마놀린은 평소 산티아고를 좋아해 그의 일손을 돕곤 했는데, 노인의 운이 다했다며 승선을 만류하는 부모 때문에 이번에는 그와 함께 배를 타지 못한다. 산티아고는 혼자 먼 바다까지 배를 끌고 가 낚싯줄을 내린다. 그의 조각배보다 훨씬 크고 힘센 청새치 한 마리가 낚싯바늘에 걸리자 산티아고는 이틀 밤낮을 넘게 그 물고기와 사투를 벌인다. 손에 쥐가 나고 낚싯줄에 쓸려 상처를 입으며 마실 물마저 다 떨어지자 포기하고 싶은 마음이 들지만 그는 마음을 다잡고 죽을힘을 다해 싸운 끝에 결국 청새치를 잡는다. 그러나 기쁨도 잠시, 뱃전에 밧줄을 묶어 매달아 놓은 물고기의 피 냄새를 맡은 상어 떼가 산티아고의 배를 쫓아온다. 그는 남은 기운을 모두 짜내어 상어 떼와 싸우지만 겨우 뭍으로 돌아와 확인해 보니 청새치는 머리와 몸통의 등뼈만 앙상하게 남아 있다. 어부들은 산티아고의 뱃전에 매달린 거대한 뼈를 보며 감탄하고, 마놀린은 안타까움에 눈물을 흘리며 먹을 것을 싸 들고 산티아고의 집으로 간다. 마놀린과 짧은 대화를 나눈 산티아고는 소년이 지켜보는 가운데 평온하게 잠이 든다.\n" +
                        "산티아고는 헤밍웨이 작품에 등장하는 전형적 주인공답게 이념보다는 본성에 충실하고 생각하는 것보다는 행동하는 것에 익숙하다. 다만 일흔의 노인인 그는 오랜 세월 동안 쌓은 연륜 덕에 보다 너그럽고 삶에 대한 혜안을 갖고 있다. 젊은 어부들이 그의 불운을 비웃어도 함께 웃어넘기며 남을 탓하지 않는다. 또한 헤밍웨이의 다른 주인공들이 다소 허무주의에 물들어 있는 반면 산티아고는 젊음을 상징하는 힘센 청새치, 시련을 상징하는 질긴 상어 떼 앞에 무릎 꿇지 않고, 물질적인 상실과 육체적인 고통에도 끝내 포기하지 않음으로써 정신적인 승리를 거둔다.\n" +
                        "\n" +
                        "좋은 일이란 오래가는 법이 없구나, 하고 그는 생각했다. 차라리 이게 한낱 꿈이었더라면 얼마나 좋을까. 이 고기는 잡은 적도 없고, 지금 이 순간 침대에 신문지를 깔고 혼자 누워 있다면 얼마나 좋을까.\n" +
                        "“하지만 인간은 패배하도록 창조된 게 아니야.” 그가 말했다. “인간은 파멸당할 수는 있을지 몰라도 패배할 수는 없어.”(『노인과 바다』 중에서)\n" +
                        "\n" +
                        "산티아고가 처한 상황과 그가 보이는 불굴의 의지는 이 작품을 쓸 당시의 헤밍웨이 자신과 연관이 깊다. 『누구를 위하여 종은 울리나』 이후 십여 년 동안 이렇다 할 작품 없이 작가로서 사형 선고를 받은 것과 다름없는 상황에서 헤밍웨이는 『노인과 바다』를 통해 작가적 생명력을 재확인하고 삶을 긍정하는 성숙한 태도를 보인다. 자칫 허무해 보이는 노인의 사투는 그가 망망대해 위에서 마놀린을 그리워하고 자신을 걱정하는 마을 사람들을 떠올리고 사람은 혼자여서는 안 된다는 사실을 절감하며 돌아와 누군가와 대화할 수 있음에 감사하는 모든 과정에서 진정한 연대와 협동에 대한 의미 있는 역설이 된다. 또한 이 작품은 얼핏 ‘인간과 자연의 싸움’을 그린 소설로 보이지만, 노인이 청새치, 상어와 벌이는 싸움은 사실상 지극히 자연스러운 먹이사슬의 한 과정이며 자연의 섭리이다. 바다를 어머니로 생각하고 자신이 잡은 물고기에게 형제애를 느끼며 자신을 자연의 일부로 받아들이는 산티아고의 모습에서는 오히려 헤밍웨이의 시대를 앞선 자연친화적, 생태주의적 세계관을 확인할 수 있다.\n" +
                        "『노인과 바다』는 감정을 절제한 강건체와 사실주의 기법을 바탕으로 하면서도 서정시 못지않은 다양한 상징과 독특한 전지적 화법을 활용해 작품의 깊이를 더한 헤밍웨이 문학의 결정판이다. 이듬해 헤밍웨이는 이 작품으로 퓰리처상을 수상했으며 1954년 그가 노벨 문학상을 수상하는 데도 『노인과 바다』가 지대한 기여를 했다. 민음사 세계문학전집에서는 헤밍웨이의 문체적 특성과 행간에 숨은 뜻까지 놓치지 않고 성실히 옮기는 데 주력했다. "),
                new GptMessage("assistant", DataSerializer.serialize(Map.of(GptConstants.CHAT_RESPONSE_KEY, "어니스트 헤밍웨이의 노인과 바다는 한 노인의 고독한 사투를 통해 인간의 의지와 삶의 의미를 담담하게 보여주는 작품으로, 짧은 분량 속에서도 깊은 여운을 전한다."))),
                new GptMessage("user", comment)
        );
        return getChatResponse(msgs).map(gptResponseParser::parseString).orElse("");
    }

    private Optional<String> getChatResponse(List<GptMessage> msgs) {
        GptRequest gptRequest = GptRequest.create(msgs);
        GptResponse gptResponse = gptClient.getChatResponse(gptRequest);

        if (CollectionUtils.isEmpty(gptResponse.getChoices())) return Optional.empty();
        return Optional.ofNullable(gptResponse.getChoices().get(0).getMessage())
                .map(msg -> msg.content());
    }


}
